{!REQUIRESCRIPT("/soap/ajax/57.0/connection.js")}
var o = new sforce.SObject("RMA_Order__c");
o.id ="{!RMA_Order__c.Id}";

function checkError(result)
{
if (!result[0].getBoolean('success')) {
throw(result[0].errors.message);
}
}
try
{
o.Resend_Flash_Email__c = true;
result = sforce.connection.update([o]);
checkError(result);
}
catch (err)
{
alert(err);
//alert('Please fill Opportunity or any other required field and then cancel the order');
}

window.location.reload();
